Convert this HTML animation into a TypeScript React component (.tsx) for my Next.js Replit project.

Requirements:
- Component name: DemandGenTileAnimation
- Export as: export default function DemandGenTileAnimation()
- Use Framer Motion for particles: import { motion } from 'framer-motion'
- Keep the exact sizing: 463px width × 632px height
- Use Tailwind CSS classes where possible, inline styles for gradients/animations
- Include proper TypeScript types for all state
- Keep all animation logic exactly as-is
- Make it self-contained (no props needed)

Here's the HTML to convert:
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Demand Generation - Multi-Channel Grid</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Roboto', sans-serif;
            background: #0f172a;
            padding: 40px 20px;
            display: flex;
            align-items: center;
            justify-content: center;
            min-height: 100vh;
        }

        .tile-container {
            width: 463px;
            height: 632px;
            background: linear-gradient(135deg, #1e293b 0%, #0f172a 100%);
            border-radius: 24px;
            padding: 32px 24px;
            display: flex;
            flex-direction: column;
            position: relative;
            overflow: hidden;
            box-shadow: 0 20px 60px rgba(0,0,0,0.5);
        }

        .tile-container::before {
            content: '';
            position: absolute;
            top: -50%;
            left: -50%;
            width: 200%;
            height: 200%;
            background: radial-gradient(circle, rgba(16, 185, 129, 0.08) 0%, transparent 70%);
            animation: rotate 20s linear infinite;
        }

        @keyframes rotate {
            from { transform: rotate(0deg); }
            to { transform: rotate(360deg); }
        }

        .grid-area {
            flex: 1;
            display: flex;
            flex-direction: column;
            position: relative;
            z-index: 1;
            padding: 20px 10px;
        }

        .grid-label {
            font-size: 11px;
            font-weight: 600;
            color: rgba(255, 255, 255, 0.4);
            text-transform: uppercase;
            letter-spacing: 1px;
            text-align: center;
            margin-bottom: 20px;
        }

        .channels-container {
            display: grid;
            grid-template-columns: repeat(4, 1fr);
            gap: 12px;
            flex: 1;
            position: relative;
        }

        .channel-column {
            display: flex;
            flex-direction: column;
            gap: 20px;
            align-items: center;
            position: relative;
        }

        .channel-header {
            width: 60px;
            height: 60px;
            border-radius: 50%;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            font-size: 24px;
            transition: all 0.3s ease;
            border: 2px solid rgba(255, 255, 255, 0.2);
        }

        .channel-header:hover {
            transform: scale(1.1);
        }

        .channel-paid .channel-header {
            background: linear-gradient(135deg, #34d399 0%, #10b981 100%);
            box-shadow: 0 4px 15px rgba(52, 211, 153, 0.4);
        }

        .channel-organic .channel-header {
            background: linear-gradient(135deg, #10b981 0%, #059669 100%);
            box-shadow: 0 4px 15px rgba(16, 185, 129, 0.4);
        }

        .channel-social .channel-header {
            background: linear-gradient(135deg, #059669 0%, #047857 100%);
            box-shadow: 0 4px 15px rgba(5, 150, 105, 0.4);
        }

        .channel-event .channel-header {
            background: linear-gradient(135deg, #047857 0%, #065f46 100%);
            box-shadow: 0 4px 15px rgba(4, 120, 87, 0.4);
        }

        .channel-name {
            font-size: 9px;
            font-weight: 700;
            color: white;
            text-transform: uppercase;
            letter-spacing: 0.3px;
            margin-top: 6px;
            text-align: center;
        }

        .channel-track {
            width: 3px;
            flex: 1;
            background: linear-gradient(to bottom, rgba(16, 185, 129, 0.3), rgba(16, 185, 129, 0.1));
            border-radius: 2px;
            position: relative;
        }

        .channel-count {
            font-size: 14px;
            font-weight: 700;
            color: white;
            background: rgba(0, 0, 0, 0.5);
            padding: 4px 8px;
            border-radius: 10px;
            position: absolute;
            top: -25px;
            right: -15px;
        }

        .pipeline-bar {
            width: 100%;
            height: 60px;
            background: linear-gradient(90deg, #34d399 0%, #10b981 50%, #047857 100%);
            border-radius: 12px;
            display: flex;
            align-items: center;
            justify-content: center;
            margin-top: 10px;
            box-shadow: 0 4px 20px rgba(16, 185, 129, 0.3);
            border: 2px solid rgba(16, 185, 129, 0.4);
            position: relative;
        }

        .pipeline-content {
            display: flex;
            align-items: center;
            gap: 12px;
        }

        .pipeline-icon {
            font-size: 28px;
        }

        .pipeline-text {
            display: flex;
            flex-direction: column;
        }

        .pipeline-label {
            font-size: 10px;
            font-weight: 600;
            color: rgba(255, 255, 255, 0.8);
            text-transform: uppercase;
            letter-spacing: 0.5px;
        }

        .pipeline-value {
            font-size: 24px;
            font-weight: 700;
            color: white;
        }

        .particle {
            position: absolute;
            width: 8px;
            height: 8px;
            background: #34d399;
            border-radius: 50%;
            box-shadow: 0 0 12px rgba(52, 211, 153, 0.8);
            pointer-events: none;
            z-index: 10;
        }

        .stats-section {
            display: grid;
            grid-template-columns: repeat(4, 1fr);
            gap: 12px;
            padding-top: 20px;
            border-top: 1px solid rgba(255, 255, 255, 0.1);
            position: relative;
            z-index: 1;
        }

        .stat-box {
            text-align: center;
        }

        .stat-value {
            font-size: 20px;
            font-weight: 700;
            color: white;
            margin-bottom: 4px;
        }

        .stat-value.green {
            color: #10b981;
        }

        .stat-label {
            font-size: 9px;
            font-weight: 600;
            color: rgba(255, 255, 255, 0.5);
            text-transform: uppercase;
            letter-spacing: 0.3px;
        }

        @keyframes flowDown {
            0% {
                top: 80px;
                opacity: 0;
            }
            10% {
                opacity: 1;
            }
            90% {
                opacity: 1;
            }
            100% {
                top: 320px;
                opacity: 0;
            }
        }
    </style>
</head>
<body>
    <div class="tile-container">
        <div class="grid-area">
            <div class="grid-label">|| INTEGRATED DEMAND CHANNELS ||</div>

            <div class="channels-container">
                <div class="channel-column channel-paid">
                    <div>
                        <div class="channel-header">💰</div>
                        <div class="channel-name">Paid</div>
                    </div>
                    <div class="channel-track">
                        <div class="channel-count" id="paidCount">0</div>
                    </div>
                </div>

                <div class="channel-column channel-organic">
                    <div>
                        <div class="channel-header">🌐</div>
                        <div class="channel-name">Organic</div>
                    </div>
                    <div class="channel-track">
                        <div class="channel-count" id="organicCount">0</div>
                    </div>
                </div>

                <div class="channel-column channel-social">
                    <div>
                        <div class="channel-header">📱</div>
                        <div class="channel-name">Social</div>
                    </div>
                    <div class="channel-track">
                        <div class="channel-count" id="socialCount">0</div>
                    </div>
                </div>

                <div class="channel-column channel-event">
                    <div>
                        <div class="channel-header">🎪</div>
                        <div class="channel-name">Events</div>
                    </div>
                    <div class="channel-track">
                        <div class="channel-count" id="eventCount">0</div>
                    </div>
                </div>
            </div>

            <div class="pipeline-bar">
                <div class="pipeline-content">
                    <div class="pipeline-icon">🚀</div>
                    <div class="pipeline-text">
                        <div class="pipeline-label">Total Pipeline</div>
                        <div class="pipeline-value" id="pipelineValue">0</div>
                    </div>
                </div>
            </div>
        </div>

        <div class="stats-section">
            <div class="stat-box">
                <div class="stat-value" id="paidStat">0</div>
                <div class="stat-label">Paid</div>
            </div>
            <div class="stat-box">
                <div class="stat-value" id="organicStat">0</div>
                <div class="stat-label">Organic</div>
            </div>
            <div class="stat-box">
                <div class="stat-value" id="socialStat">0</div>
                <div class="stat-label">Social</div>
            </div>
            <div class="stat-box">
                <div class="stat-value green" id="eventStat">0</div>
                <div class="stat-label">Events</div>
            </div>
        </div>
    </div>

    <script>
        let pipelineTotal = 0;
        let channelTotals = { paid: 0, organic: 0, social: 0, event: 0 };
        let channelCounts = { paid: 0, organic: 0, social: 0, event: 0 };

        const channels = [
            { name: 'paid', x: 55, color: '#34d399' },
            { name: 'organic', x: 155, color: '#10b981' },
            { name: 'social', x: 255, color: '#059669' },
            { name: 'event', x: 355, color: '#047857' }
        ];

        function updateStats() {
            document.getElementById('pipelineValue').textContent = pipelineTotal;
            document.getElementById('paidCount').textContent = channelCounts.paid;
            document.getElementById('organicCount').textContent = channelCounts.organic;
            document.getElementById('socialCount').textContent = channelCounts.social;
            document.getElementById('eventCount').textContent = channelCounts.event;
            document.getElementById('paidStat').textContent = channelTotals.paid;
            document.getElementById('organicStat').textContent = channelTotals.organic;
            document.getElementById('socialStat').textContent = channelTotals.social;
            document.getElementById('eventStat').textContent = channelTotals.event;
        }

        function createParticle() {
            const channel = channels[Math.floor(Math.random() * channels.length)];

            const particle = document.createElement('div');
            particle.className = 'particle';

            const container = document.querySelector('.grid-area');
            particle.style.left = channel.x + 'px';
            particle.style.top = '80px';
            particle.style.animation = 'flowDown 2.2s linear';
            particle.style.background = channel.color;
            particle.style.boxShadow = `0 0 12px ${channel.color}`;

            container.appendChild(particle);

            channelCounts[channel.name]++;
            updateStats();

            // 70% make it to pipeline
            const makesIt = Math.random() > 0.3;

            setTimeout(() => {
                channelCounts[channel.name]--;

                if (makesIt) {
                    pipelineTotal++;
                    channelTotals[channel.name]++;
                } else {
                    particle.style.opacity = '0';
                }

                updateStats();
            }, 1800);

            setTimeout(() => {
                particle.remove();
            }, 2200);
        }

        // High frequency for demand gen (multiple channels running)
        setInterval(createParticle, 600);
        updateStats();
    </script>
</body>
</html>

