import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React from 'react';
import DemandGenTileAnimation from './components/DemandGenTileAnimation';

const App: React.FC = () => {
  return (
    <div className="flex items-center justify-center p-10">
      <DemandGenTileAnimation />
    </div>
  );
};

export default App;

export type ChannelId = 'paid' | 'organic' | 'social' | 'event';

export interface Channel {
  id: ChannelId;
  name: string;
  icon: string;
  color: string;
  gradient: string;
}

export interface Particle {
  id: number;
  channelId: ChannelId;
  color: string;
}

export interface Stats {
  paid: number;
  organic: number;
  social: number;
  event: number;
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Channel, ChannelId, Particle, Stats } from '../types';

const CHANNELS: Channel[] = [
  { id: 'paid', name: 'Paid', icon: '💰', color: '#34d399', gradient: 'linear-gradient(135deg, #34d399 0%, #10b981 100%)' },
  { id: 'organic', name: 'Organic', icon: '🌐', color: '#10b981', gradient: 'linear-gradient(135deg, #10b981 0%, #059669 100%)' },
  { id: 'social', name: 'Social', icon: '📱', color: '#059669', gradient: 'linear-gradient(135deg, #059669 0%, #047857 100%)' },
  { id: 'event', name: 'Events', icon: '🎪', color: '#047857', gradient: 'linear-gradient(135deg, #047857 0%, #065f46 100%)' },
];

export default function DemandGenTileAnimation() {
  const [pipelineTotal, setPipelineTotal] = useState<number>(0);
  const [channelTotals, setChannelTotals] = useState<Stats>({ paid: 0, organic: 0, social: 0, event: 0 });
  const [channelActiveCounts, setChannelActiveCounts] = useState<Stats>({ paid: 0, organic: 0, social: 0, event: 0 });
  const [particles, setParticles] = useState<Particle[]>([]);

  const particleIdRef = useRef<number>(0);

  const spawnParticle = useCallback(() => {
    const randomChannel = CHANNELS[Math.floor(Math.random() * CHANNELS.length)];
    const newId = ++particleIdRef.current;

    const newParticle: Particle = {
      id: newId,
      channelId: randomChannel.id,
      color: randomChannel.color,
    };

    // Increment active count
    setChannelActiveCounts(prev => ({
      ...prev,
      [randomChannel.id]: prev[randomChannel.id] + 1
    }));

    // Add to particles array
    setParticles(prev => [...prev, newParticle]);

    // Handle pipeline logic after travel (1.8s mark)
    const makesIt = Math.random() > 0.3;

    setTimeout(() => {
      // Decrement active count
      setChannelActiveCounts(prev => ({
        ...prev,
        [randomChannel.id]: Math.max(0, prev[randomChannel.id] - 1)
      }));

      if (makesIt) {
        setPipelineTotal(prev => prev + 1);
        setChannelTotals(prev => ({
          ...prev,
          [randomChannel.id]: prev[randomChannel.id] + 1
        }));
      }
    }, 1800);

    // Clean up particle from DOM
    setTimeout(() => {
      setParticles(prev => prev.filter(p => p.id !== newId));
    }, 2200);
  }, []);

  useEffect(() => {
    const interval = setInterval(spawnParticle, 600);
    return () => clearInterval(interval);
  }, [spawnParticle]);

  return (
    <div className="relative w-[463px] h-[632px] rounded-[24px] overflow-hidden flex flex-col p-8 bg-gradient-to-br from-[#1e293b] to-[#0f172a] shadow-2xl border border-slate-700/50">
      {/* Background Rotating Glow Effect */}
      <div 
        className="absolute -top-1/2 -left-1/2 w-[200%] h-[200%] opacity-20 pointer-events-none animate-slow-rotate"
        style={{ background: 'radial-gradient(circle, rgba(16, 185, 129, 0.15) 0%, transparent 70%)' }}
      />

      <div className="relative z-10 flex flex-col flex-1">
        <div className="text-[11px] font-bold text-slate-400 uppercase tracking-widest text-center mb-5">
          || Integrated Demand Channels ||
        </div>

        <div className="relative flex-1 grid grid-cols-4 gap-3 mb-4">
          {CHANNELS.map((channel) => (
            <div key={channel.id} className="flex flex-col items-center gap-5 relative">
              {/* Channel Header */}
              <div className="flex flex-col items-center group">
                <div 
                  className="w-[60px] h-[60px] rounded-full flex items-center justify-center text-2xl transition-transform duration-300 group-hover:scale-110 border-2 border-white/20 shadow-lg"
                  style={{ background: channel.gradient }}
                >
                  {channel.icon}
                </div>
                <div className="text-[9px] font-bold text-white uppercase tracking-tighter mt-1.5 text-center">
                  {channel.name}
                </div>
              </div>

              {/* Channel Track */}
              <div className="relative flex-1 w-[3px] bg-gradient-to-b from-emerald-500/30 to-emerald-500/10 rounded-full">
                {/* Active Count Badge */}
                <AnimatePresence>
                  {channelActiveCounts[channel.id] > 0 && (
                    <motion.div 
                      initial={{ scale: 0, opacity: 0 }}
                      animate={{ scale: 1, opacity: 1 }}
                      exit={{ scale: 0, opacity: 0 }}
                      className="absolute -top-6 -right-4 bg-black/60 text-white text-[14px] font-bold px-2 py-1 rounded-[10px] backdrop-blur-sm border border-white/10 z-20"
                    >
                      {channelActiveCounts[channel.id]}
                    </motion.div>
                  )}
                </AnimatePresence>

                {/* Flowing Particles */}
                {particles
                  .filter(p => p.channelId === channel.id)
                  .map(particle => (
                    <motion.div
                      key={particle.id}
                      initial={{ top: 0, opacity: 0, scale: 0.5 }}
                      animate={{ 
                        top: 240, 
                        opacity: [0, 1, 1, 0],
                        scale: [0.5, 1.2, 1.2, 0.8]
                      }}
                      transition={{ 
                        duration: 2.2, 
                        ease: "linear",
                        times: [0, 0.1, 0.9, 1]
                      }}
                      className="absolute left-1/2 -translate-x-1/2 w-2 h-2 rounded-full z-10"
                      style={{ 
                        backgroundColor: particle.color,
                        boxShadow: `0 0 12px ${particle.color}`
                      }}
                    />
                  ))}
              </div>
            </div>
          ))}
        </div>

        {/* Pipeline Bar */}
        <div 
          className="relative w-full h-[60px] rounded-xl flex items-center justify-center mt-2 border-2 border-emerald-500/40 shadow-[0_4px_20px_rgba(16,185,129,0.3)]"
          style={{ background: 'linear-gradient(90deg, #34d399 0%, #10b981 50%, #047857 100%)' }}
        >
          <div className="flex items-center gap-3">
            <span className="text-[28px]">🚀</span>
            <div className="flex flex-col">
              <span className="text-[10px] font-semibold text-white/80 uppercase tracking-wider">Total Pipeline</span>
              <span className="text-2xl font-bold text-white leading-none">
                {pipelineTotal.toLocaleString()}
              </span>
            </div>
          </div>
        </div>
      </div>

      {/* Stats Section */}
      <div className="relative z-10 grid grid-cols-4 gap-3 pt-5 mt-5 border-t border-white/10">
        {CHANNELS.map((channel) => (
          <div key={`${channel.id}-stat`} className="text-center">
            <div className={`text-[20px] font-bold ${channel.id === 'event' ? 'text-emerald-500' : 'text-white'}`}>
              {channelTotals[channel.id]}
            </div>
            <div className="text-[9px] font-semibold text-white/50 uppercase tracking-wider">
              {channel.name}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Channel, ChannelId, Particle, Stats } from '../types';

const CHANNELS: Channel[] = [
  { id: 'paid', name: 'Paid', icon: '💰', color: '#818cf8', gradient: 'linear-gradient(135deg, #818cf8 0%, #6366f1 100%)' },
  { id: 'organic', name: 'Organic', icon: '🌐', color: '#a855f7', gradient: 'linear-gradient(135deg, #a855f7 0%, #8b5cf6 100%)' },
  { id: 'social', name: 'Social', icon: '📱', color: '#c084fc', gradient: 'linear-gradient(135deg, #c084fc 0%, #a855f7 100%)' },
  { id: 'event', name: 'Events', icon: '🎪', color: '#2dd4bf', gradient: 'linear-gradient(135deg, #2dd4bf 0%, #14b8a6 100%)' },
];

export default function DemandGenTileAnimation() {
  const [pipelineTotal, setPipelineTotal] = useState<number>(1200); // Start with some data for "feel"
  const [channelTotals, setChannelTotals] = useState<Stats>({ paid: 450, organic: 320, social: 280, event: 150 });
  const [channelActiveCounts, setChannelActiveCounts] = useState<Stats>({ paid: 0, organic: 0, social: 0, event: 0 });
  const [particles, setParticles] = useState<Particle[]>([]);

  const particleIdRef = useRef<number>(0);

  const spawnParticle = useCallback(() => {
    const randomChannel = CHANNELS[Math.floor(Math.random() * CHANNELS.length)];
    const newId = ++particleIdRef.current;

    const newParticle: Particle = {
      id: newId,
      channelId: randomChannel.id,
      color: randomChannel.color,
    };

    setChannelActiveCounts(prev => ({
      ...prev,
      [randomChannel.id]: prev[randomChannel.id] + 1
    }));

    setParticles(prev => [...prev, newParticle]);

    const makesIt = Math.random() > 0.3;

    setTimeout(() => {
      setChannelActiveCounts(prev => ({
        ...prev,
        [randomChannel.id]: Math.max(0, prev[randomChannel.id] - 1)
      }));

      if (makesIt) {
        setPipelineTotal(prev => prev + 1);
        setChannelTotals(prev => ({
          ...prev,
          [randomChannel.id]: prev[randomChannel.id] + 1
        }));
      }
    }, 1500);

    setTimeout(() => {
      setParticles(prev => prev.filter(p => p.id !== newId));
    }, 1800);
  }, []);

  useEffect(() => {
    const interval = setInterval(spawnParticle, 700);
    return () => clearInterval(interval);
  }, [spawnParticle]);

  const totalReach = Object.values(channelTotals).reduce((a, b) => a + b, 0);

  return (
    <div className="relative w-[463px] h-[632px] rounded-[32px] overflow-hidden flex flex-col p-6 bg-[#030712] shadow-2xl border border-white/5 font-sans">
      {/* Subtle Glow Background */}
      <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_50%_0%,rgba(99,102,241,0.1),transparent_70%)] pointer-events-none" />

      {/* Header */}
      <div className="flex items-center justify-between mb-8 relative z-10">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
              <path d="M3 17l6-6 4 4 8-8" />
              <path d="M17 7h4v4" />
            </svg>
          </div>
          <h2 className="text-lg font-bold text-white tracking-tight">Performance Analytics</h2>
        </div>
        <div className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-emerald-500/10 border border-emerald-500/20">
          <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
          <span className="text-[11px] font-bold text-emerald-500 uppercase tracking-wider">Live</span>
        </div>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-2 gap-4 mb-6 relative z-10">
        <div className="bg-[#0f172a] p-5 rounded-2xl border border-white/5">
          <div className="text-slate-400 text-sm font-medium mb-1">Total Reach</div>
          <div className="text-2xl font-bold text-white mb-2">{(totalReach / 10).toFixed(1)}K</div>
          <div className="text-emerald-500 text-sm font-bold flex items-center gap-1">
            <span>+12.3%</span>
          </div>
        </div>
